def sanitize_text(text):
    """Sanitize and normalize input text to prevent evasion attacks"""
    if not isinstance(text, str):
        raise ValueError("Input must be a string")
    
    # Length validation
    if len(text) < MIN_EMAIL_LENGTH or len(text) > MAX_EMAIL_LENGTH:
        raise ValueError(f"Email length must be between {MIN_EMAIL_LENGTH} and {MAX_EMAIL_LENGTH} characters")
    
    # Convert to lowercase
    text = text.lower()
    
    # Remove excessive whitespace and normalize
    text = re.sub(r'\s+', ' ', text)
    
    # Remove zero-width characters and other unicode tricks
    text = re.sub(r'[\u200b-\u200f\u202a-\u202e\ufeff]', '', text)
    
    # Normalize common obfuscation techniques
    # Replace repeated characters (e.g., "freeee" -> "free")
    text = re.sub(r'(.)\1{2,}', r'\1\1', text)
    
    # Remove excessive punctuation
    text = re.sub(r'[!?]{3,}', '!!', text)
    
    # Normalize leetspeak and common substitutions
    leetspeak_map = {
        '0': 'o', '1': 'i', '3': 'e', '4': 'a', '5': 's', 
        '7': 't', '8': 'b', '@': 'a', '$': 's', '€': 'e'
    }
    for leet, normal in leetspeak_map.items():
        text = text.replace(leet, normal)
    
    # Remove HTML tags
    text = re.sub(r'<[^>]+>', '', text)
    
    # Remove URLs (keep the domain for analysis)
    text = re.sub(r'https?://[^\s]+', 'url', text)
    
    # Normalize word boundaries with special characters
    text = re.sub(r'[^\w\s]', ' ', text)
    
    # Remove extra spaces again after all transformations
    text = re.sub(r'\s+', ' ', text).strip()
    
    # Validate word lengths to prevent adversarial inputs
    words = text.split()
    words = [w[:MAX_WORD_LENGTH] for w in words if len(w) > 0]
    text = ' '.join(words)
    
    return text

def extract_additional_features(text):
    """Extract additional features to make model more robust"""
    features = {}
    
    # Character-level features
    features['uppercase_ratio'] = sum(1 for c in text if c.isupper()) / max(len(text), 1)
    features['digit_ratio'] = sum(1 for c in text if c.isdigit()) / max(len(text), 1)
    features['special_char_ratio'] = sum(1 for c in text if not c.isalnum() and not c.isspace()) / max(len(text), 1)
    
    # Word-level features
    words = text.split()
    features['avg_word_length'] = np.mean([len(w) for w in words]) if words else 0
    features['num_words'] = len(words)
    
    # Spam indicators
    features['has_money_symbol'] = 1 if any(c in text for c in ['$', '€', '£']) else 0
    features['exclamation_count'] = min(text.count('!'), 10)  # Cap at 10
    features['question_count'] = min(text.count('?'), 10)
    
    return features

